return [
  {
    json: {
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      title: 'Example source item',
      canonical_url: 'https://example.com/post',
      original_id: 'yt:abc123',
      author: 'OpenAI',
      published_at: '2026-04-17T09:00:00-04:00',
      raw_html: '<p>This is the original HTML body.</p>',
      raw_text: 'This is the original HTML body.',
      media_type: 'text'
    }
  }
];

const crypto = require('crypto');

const stableHash = (value) => crypto.createHash('sha256').update(String(value), 'utf8').digest('hex');
const stripHtml = (value = '') => String(value)
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/\s+/g, ' ')
  .trim();

const canonicalUrl = String($json.canonical_url || '').trim();
const sourceType = String($json.source_type || 'manual').trim() || 'manual';
const sourceName = String($json.source_name || 'unknown-source').trim() || 'unknown-source';
const originalId = String($json.original_id || '').trim();
const title = String($json.title || 'untitled').trim() || 'untitled';
const author = String($json.author || '').trim();
const publishedAt = new Date($json.published_at || Date.now()).toISOString();
const ingestedAt = new Date().toISOString();
const mediaType = String($json.media_type || 'text').trim() || 'text';
const contentHtml = String($json.raw_html || '').trim();
const contentText = String($json.raw_text || stripHtml(contentHtml)).trim();
const itemKey = canonicalUrl || (sourceType && originalId ? `${sourceType}:${originalId}` : '') || [title, publishedAt, author].filter(Boolean).join('::');
const itemId = stableHash(itemKey);

return {
  json: {
    item_id: itemId,
    source_type: sourceType,
    source_name: sourceName,
    original_id: originalId,
    canonical_url: canonicalUrl,
    title,
    author,
    published_at: publishedAt,
    ingested_at: ingestedAt,
    media_type: mediaType,
    content_text: contentText,
    content_html: contentHtml,
    upstream_task_id: '',
    upstream_view_token: '',
    upstream_summary: '',
    content_hash: `sha256:${stableHash(contentText)}`,
    score: 0,
    category: 'pending',
    tags: ['inbox', 'ai-information-processor'],
    dedupe_action: 'full_push',
    status: 'raw',
    vault_path: ''
  }
};
